fun shortestPath(grid: Array<IntArray>): Int {
    // TODO: BFS from (0,0) to (rows-1, cols-1)
    // Return number of steps, or -1 if no path exists
    // Can move: up, down, left, right
}

questions.solution:
fun shortestPath(grid: Array<IntArray>): Int {
    val rows = grid.size
    val cols = grid[0].size
    if (grid[0][0] == 1 || grid[rows-1][cols-1] == 1) return -1

    val queue = ArrayDeque<Triple<Int, Int, Int>>() // row, col, steps
    val visited = Array(rows) { BooleanArray(cols) }

    queue.addLast(Triple(0, 0, 1))
    visited[0][0] = true

    val dirs = intArrayOf(-1, 0, 1, 0, -1) // up, right, down, left trick

    while (queue.isNotEmpty()) {
        val (r, c, steps) = queue.removeFirst()
        if (r == rows - 1 && c == cols - 1) return steps

        for (d in 0 until 4) {
            val nr = r + dirs[d]
            val nc = c + dirs[d + 1]
            if (nr in 0 until rows && nc in 0 until cols &&
                !visited[nr][nc] && grid[nr][nc] == 0) {
                visited[nr][nc] = true
                queue.addLast(Triple(nr, nc, steps + 1))
            }
        }
    }
    return -1
}

